import psycopg2
from psycopg2 import sql

def get_db_connection():
    return psycopg2.connect(
        dbname='your_db_name',
        user='your_db_user',
        password='your_db_password',
        host='your_db_host',
        port='your_db_port'
    )

def search_users(username=None, email=None, role=None, status=None):
    conn = get_db_connection()
    cur = conn.cursor()

    base_query = sql.SQL("SELECT id, username, email, role, status FROM users")
    filters = []
    values = []

    if username:
        filters.append(sql.SQL("username = %s"))
        values.append(username)
    if email:
        filters.append(sql.SQL("email = %s"))
        values.append(email)
    if role:
        filters.append(sql.SQL("role = %s"))
        values.append(role)
    if status:
        filters.append(sql.SQL("status = %s"))
        values.append(status)

    if filters:
        query = base_query + sql.SQL(" WHERE ") + sql.SQL(" AND ").join(filters)
    else:
        query = base_query

    cur.execute(query, values)
    results = cur.fetchall()

    cur.close()
    conn.close()

    return results

